+/**
+ * @brief anonymous log.
+ *
+ * @param log original log
+ * @return std::string string value after anonymous
+ */
+std::string anonymous_log(std::string log)
+{
+    std::string anonymousLog(log);
+    if (log != "") {
+        anonymousLog = log.substr(0, 1) + DEFAULT_ANONYMOUS;
+    }
+    return anonymousLog;
+}
