+        SETTING_LOG_ERROR("napi_queue_async_work error");
+        napi_delete_reference(env, asyncCallbackInfo->callbackRef);
+        napi_delete_async_work(env, asyncCallbackInfo->asyncWork);
+        asyncCallbackInfo->dataAbilityHelper = nullptr;
